@strawberry.type
class Seller:
    id: int
    name: str


@strawberry.type
class Category:
    id: int
    name: str


@strawberry.type
class Review:
    id: int
    rating: int
    comment: Optional[str]


@strawberry.type
class Image:
    id: int
    url: str
    alt_text: Optional[str]


@strawberry.type
class Product:
    id: int
    name: str
    description: Optional[str]
    price: float
    seller: Seller
    reviews: List[Review]
    categories: List[Category]
    images: List[Image]


def to_seller(model: SellerModel) -> Seller:
    return Seller(id=model.id, name=model.name)


def to_category(model: CategoryModel) -> Category:
    return Category(id=model.id, name=model.name)


def to_review(model: ReviewModel) -> Review:
    return Review(id=model.id, rating=model.rating, comment=model.comment)


def to_image(model: ImageModel) -> Image:
    return Image(id=model.id, url=model.url, alt_text=model.alt_text)


def to_product(model: ProductModel) -> Product:
    return Product(
        id=model.id,
        name=model.name,
        description=model.description,
        price=model.price,
        seller=to_seller(model.seller),
        reviews=[to_review(review) for review in model.reviews],
        categories=[to_category(category) for category in model.categories],
        images=[to_image(image) for image in model.images],
    )


@strawberry.type
class Query:
    @strawberry.field
    def products(self) -> List[Product]:
        with get_session() as session:
            stmt = (
                select(ProductModel)
                .options(
                    selectinload(ProductModel.seller),
                    selectinload(ProductModel.reviews),
                    selectinload(ProductModel.categories),
                    selectinload(ProductModel.images),
                )
            )
            products = session.scalars(stmt).all()
            return [to_product(product) for product in products]

    @strawberry.field
    def product(self, id: int) -> Optional[Product]:
        with get_session() as session:
            stmt = (
                select(ProductModel)
                .where(ProductModel.id == id)
                .options(
                    selectinload(ProductModel.seller),
                    selectinload(ProductModel.reviews),
                    selectinload(ProductModel.categories),
                    selectinload(ProductModel.images),
                )
            )
            product = session.scalar(stmt)
            return to_product(product) if product else None


schema = strawberry.Schema(query=Query)

